import React, { useState } from 'react';
import { ErrorMessage, useField, Field, useFormikContext } from 'formik';
import { useTranslation } from 'react-i18next';
import "./KarimField.scss";
import { FaExclamationCircle } from 'react-icons/fa';
import Select from 'react-select';
import Datepickertofrom from './Datepickertofrom';


type KarimFieldProps = {
  name: string;
  name2:string
  type: string;
  placeholder?:string
  label ?:string
  className?: string;
  option?: any
  isMulti?: boolean
  Disabled?: boolean
};

const KarimField: React.FC<KarimFieldProps> = (
  { 
    name,
    name2,
    type,
    placeholder,
    label,
    className = "",
    option = [],
    isMulti,
    Disabled,
    ...props
  }) => {
  const { t } = useTranslation();
  const [field, meta] = useField({ name, ...props });
  const formik = useFormikContext<any>();

  const isError = meta.touched && meta.error;
  const hasValue = Array.isArray(field.value) ? field.value.length > 0 :  typeof field.value === "object" ? Object.keys(field.value).length > 0 : !!field.value;
  const inputClass = isError ? `${className} is-invalid` : hasValue ? `${className}hasValue` : Disabled ? `${className} Disabled ` :  `${className} `;

  const [showSecondDate, setShowSecondDate] = useState<boolean>(false);
  const [firstDate, setFirstDate] = useState<string>('');
  const today = new Date().toISOString().slice(0, 10); // Get today's date in YYYY-MM-DD format

  const handleFirstDateChange = (event:any) => {
    const { value } = event.target;
    setFirstDate(value);
    setShowSecondDate(true);
  };




  if (type === "checkbox") {
    return (
      <div className="KarimCheckbox">

        <label className="cont">
          <input
            checked={formik.values[name] === 1}
            type="checkbox"
            name={name}
            onChange={() =>
              formik.setFieldValue(name, formik.values[name] === 1 ? 0 : 1)} />
          <span />
          {label}
        </label>

      </div>



    )
  } else if (type === "select") {
    //////////   option must be have name and id     
    return (
      <div className='KarimSelect'>
                <label htmlFor={field.name} className="text">      {label}    </label>


        <Field
          as={Select}
          className={inputClass}
          classNamePrefix="react-select"
          name={name}
          value={formik.getFieldProps(name).value}
          onChange={(opt: any) => formik.setFieldValue(name, opt)}
          options={convert_data_to_select(option)}
          isMulti={!!isMulti}
          isDisabled={!!Disabled}
        placeholder={placeholder}

        />
        <ErrorMessage name={name}>
          {(msg: any) => <span className="field-error text-danger">{t(msg)}</span>}
        </ErrorMessage>
      </div>


    )

  }
  else if (type === "DataRange") {


    return (
      <div className='Datepicker'>
      <div className="KarimField">
        <label htmlFor="firstDate" className="text">
          {"date from"} {""}
        </label>
        <input
          type="date"
          id="firstDate"
          name="firstDate"
          className={inputClass}
          value={firstDate}
          onChange={handleFirstDateChange}
          min={today}
        />
      </div>

        <div className="KarimField">
          <label htmlFor="secondDate" className="text">
        {firstDate == ""  ?  `select ${name}`  : "date to"  } 
          </label>
          <input
            type="date"
            id="secondDate"
            name="secondDate"
            className={inputClass}
            min={firstDate}
            readOnly={firstDate === "" ? true : false} 


          />
        </div>
    </div>


    )

  }

  else {
    return (
      <div className="KarimField">
        <label htmlFor={field.name} className="text">
          {isError ? <span className='isErrorIcon'> <FaExclamationCircle /></span> : ""}  {label} {""}
          <ErrorMessage name={field.name}>
            {(msg: any) => <span className="field-error text-danger isErrorIcon">{t(msg)} <FaExclamationCircle /> </span>}
          </ErrorMessage>
        </label>

        <Field
          type={type}
          placeholder={placeholder}
          name={field.name}
          className={inputClass}
        />


      </div>



    );
  }
};

export default KarimField;


export const convert_data_to_select = (array = []) => {
  if (typeof array === 'undefined' || !Array.isArray(array)) {
    throw new Error("Expected an array argument")
  }
  let new_array :any = []
  array.map((e:any) => new_array.push({ label: e?.name, value: e?.id }))


  return new_array
}
